const t=`{% block sw_base_filter %} <div class="sw-base-filter"> {% block sw_base_filter_headline %} <div class="sw-base-filter__headline"> <h4 class="sw-base-filter__title"> {{ title }} </h4> <a v-if="showResetButton" class="sw-base-filter__reset" role="button" tabindex="0" @click="resetFilter" @keydown.enter="resetFilter" >{{ $t('sw-base-filter.resetButton') }}</a> </div> {% endblock %} {% block sw_base_filter_content %} <slot></slot> {% endblock %} </div> {% endblock %}`,s={template:t,emits:["filter-reset"],props:{title:{type:String,required:!0},showResetButton:{type:Boolean,required:!0},active:{type:Boolean,required:!0}},watch:{active(e){e||this.resetFilter()}},methods:{resetFilter(){this.$emit("filter-reset")}}};export{s as default};
